```python
class InvestmentAdvisor:
    def __init__(self):
        self.investments = {
            "stocks": ["Apple Inc.", "Microsoft Corp.", "Tesla Inc."],
            "bonds": ["US Treasury 10 Year Note", "Corporate Bond Index Fund"],
            "other": ["Gold ETF", "Real Estate Investment Trust (REIT)"]
        }

    def get_investment_suggestions(self, risk_level, investment_timeframe, investment_goal):
        """
        根据用户提供的风险水平、投资期限和投资目标来推荐投资产品。
        """
        if risk_level == "low":
            if investment_timeframe == "short":
                suggestions = self.investments["bonds"]
            elif investment_timeframe == "long":
                suggestions = self.investments["other"]
        elif risk_level == "high":
            if investment_timeframe == "short":
                suggestions = self.investments["stocks"]
            elif investment_timeframe == "long":
                suggestions = self.investments["other"]
        else:
            suggestions = self.investments["stocks"]

        return suggestions

# 示例用法
advisor = InvestmentAdvisor()
risk_level = input("请输入您的风险承受能力（低、中、高）：")
investment_timeframe = input("请输入您的投资期限（短期、长期）：")
investment_goal = input("请输入您的投资目标（例如：资本增值、收益、保值）：")

suggestions = advisor.get_investment_suggestions(risk_level, investment_timeframe, investment_goal)
print("根据您的信息，我们为您推荐的投资产品有：")
for suggestion in suggestions:
    print(suggestion)
```

